module RefModule(in, enable, clear, clk, out);input [5:0] in;
  input enable;
  input clear;
  input clk;
  output [5:0] out;
  wire [5:0] _tap_in = in & {6{1'b1}};


  reg [5:0] states;

  always @ (posedge clk) begin
    if(enable && clear) begin
      states = 6'b000000;
    end

    else if(enable) begin
      states <= in;
    end
  end

  assign out = states;

endmodule
